# Prompt: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

class CartItem:
    def __init__(self, name, price, quantity):
        self.name = name
        self.price = price
        self.quantity = quantity

class Order:
    def __init__(self, items, total_price, tax, discount_applied):
        self.items = items
        self.total_price = total_price
        self.tax = tax
        self.discount_applied = discount_applied

def validate_cart_items(cart_items):
    if not all(item.quantity > 0 for item in cart_items):
        raise ValueError("All items must have a quantity greater than zero.")
    return cart_items

def apply_discount_codes(cart_items, discount_code, user_permissions):
    valid_codes = {
        "ADMIN123": {"discount": 0.25, "permissions": ["admin"]},
        "USERDISC": {"discount": 0.10, "permissions": []}
    }
    
    if discount_code not in valid_codes:
        raise ValueError("Invalid discount code.")
    
    discount_info = valid_codes[discount_code]
    if discount_info["permissions"] and not any(perm in user_permissions for perm in discount_info["permissions"]):
        raise PermissionError("Discount code is restricted to specific user permissions.")
    
    total_price = sum(item.price * item.quantity for item in cart_items)
    discounted_total = total_price * (1 - discount_info["discount"])
    
    return [(item, item.price) for item in cart_items], discounted_total

def calculate_tax(cart_items):
    tax_rate = 0.08
    total_price = sum(item.price * item.quantity for item in cart_items)
    tax_amount = total_price * tax_rate
    return tax_amount

def process_payment(total_price):
    # Simulate payment processing
    print(f"Processing payment of ${total_price:.2f}.")
    return True

def create_order_record(cart_items, total_price, tax, discount_applied):
    order = Order(cart_items, total_price, tax, discount_applied)
    print(f"Order created with total price: ${order.total_price:.2f}, tax: ${order.tax:.2f}, discount applied: {order.discount_applied}")
    return order

def checkout_process(cart_items, discount_code, user_permissions):
    try:
        validated_cart = validate_cart_items(cart_items)
        cart_with_prices, discounted_total = apply_discount_codes(validated_cart, discount_code, user_permissions)
        tax_amount = calculate_tax(cart_with_prices)
        final_price = discounted_total + tax_amount
        payment_success = process_payment(final_price)
        
        if payment_success:
            return create_order_record(cart_with_prices, final_price, tax_amount, True)
        else:
            raise Exception("Payment failed.")
    except (ValueError, PermissionError) as e:
        print(f"Checkout failed: {e}")
        return None

# Example usage
cart_items = [CartItem("Item1", 10.0, 2), CartItem("Item2", 5.0, 3)]
user_permissions = ["admin"]
order = checkout_process(cart_items, "ADMIN123", user_permissions)